#include <stdio.h>

int linearSearch(int arr[], int n, int target) {
    for (int i = 0; i < n; i++) {
        if (arr[i] == target) return i;
    }
    return -1;
}

int main() {
    int arr[] = {10, 20, 80, 30, 60};
    int target = 30;
    int index = linearSearch(arr, 5, target);
    if (index != -1) printf("Found at index %d\n", index);
    else printf("Not found\n");
    return 0;
}

